export const getAgentPlaygroundGraphsExecutionsListUrl = (graphId: string,
    params?: AgentPlaygroundGraphsExecutionsListParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (Array.isArray(value)) {
      value
        .filter((item) => item !== undefined && item !== null)
        .forEach((item) => normalizedParams.append(key, item.toString()))
    } else if (value !== undefined && value !== null) {
      normalizedParams.append(key, value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/agent-playground/graphs/${graphId}/executions/?${stringifiedParams}` : `/agent-playground/graphs/${graphId}/executions/`
}

